VALUES
  ('cpa-moex-00276', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司製造3D列印機，對於每台機器，使用$5,100的直接材料和$3,900的直接人工，直接 人工每小時$200。製造費用按每直接人工小時$250計算。如果每台機器售價為$14,250，A公 司銷售70台機器所賺取的毛利為何？', '["$4,875", "$26,250", "$81,900", "$262,250"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00277', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司資料如下： 單位售價 $500 單位變動成本 $120 總固定成本$280,000 假設所得稅率20% 如果想有稅後淨利$80,000，要銷售多少單位商品？ （請四捨五入至個位數）', '["720", "760", "947", "1,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00278', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司生產及銷售90,000單位商品，銷貨收入$4,500,000 製造成本：變動：$2,000,000，固定：$1,200,000 銷售成本：變動：$80,000，固定：$182,000 行政成本：變動：$380,000，固定：$250,000 如果A公司的銷貨收入增加8%，則稅前淨利成長率為何？', '["8%", "24%", "32%", "40%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00279', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A 公司的總固定成本為$400,000，而單位變動成本為售價的 75%。如果 A 公司想從 500,000 單位的銷售量中獲得$100,000的稅前利潤，則產品售價？', '["$1.00", "$1.50", "$2.00", "$4.00"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00280', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司只生產一種產品，單位售價$100，單位變動成本$80，去年損益平衡不賺也不賠，今年 預計稅前淨利$60,000，則今年A公司必須比去年多銷售多少單位？', '["2,000單位", "3,000單位", "4,000單位", "5,000單位"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00281', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '有關轉撥計價，下列敘述何者錯誤？', '["移轉價格指勞務或中間產品由企業內部之某一部門移轉至另一部門時所計算之價格", "基於績效考量，轉出部門及轉入部門皆希望採用移轉價格較高者", "在決定移轉價格時，通常需考量轉出部門及轉入部門之相對競爭力及中間產品之市場競爭 情況等因素", "在決定跨國部門移轉價格時，通常需考量國際間稅負條件之差異及所得匯出之限制等因素"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00282', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司生產檜木餐桌，單位製造成本$1,000，其中70%為變動成本，30%為固定成本，A公司 的長期訂價決策為全部成本加成25%。A公司目前有閒置產能，可再接受現有民宿業者訂購 50張餐桌（屬特殊訂單，非例行性訂單），此訂單最低總成本？', '["$35,000", "$43,750", "$50,000", "$62,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00283', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司為電腦製造商，單位售價$30,000，單位變動成本$15,000，單位固定成本$5,000。A公 司正常產能為 50,000 台，目前使用率為 70%。今收到一張短期特殊訂單，訂購數量 20,000 台，價格為每台$25,000，且現有市場價格及需求不受影響。在不考慮擴充產能與加班的情況 下，下列敘述何者正確？', '["A公司應接此訂單，淨利會增加$125,000,000", "A公司應接此訂單，淨利會增加$650,000,000", "A公司不應接此訂單，淨利會減少$125,000,000", "A公司不應接此訂單，淨利會減少$400,000,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00284', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司製造毛巾，目前面臨一項特殊訂單的決策。當管理者決定是否要接受此特殊訂單時， 下列那個項目不需要考慮？', '["分析產品的製造成本", "分析產品的行銷人員每月固定薪資", "考慮特殊訂單對毛巾未來價格的影響", "了解公司是否有閒置產能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00285', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司生產甲、乙、丙、丁四種不同的產品，目前市場對於這四種產品均有需求，每單位售 價與每單位成本資訊如下： 甲 乙 丙 丁 售價 $29 $35 $42 $42 直接材料 5 5 5 5 直接人工 6 6 12 6 變動製造費用（每機器小時$5） 5 10 10 15 固定製造費用 6 6 6 6 假如A公司的生產機器有一台發生故障，只能選擇一種產品生產，選擇生產那一種產品將帶 來最高的利潤？', '["甲", "乙", "丙", "丁"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00286', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '有關攸關成本與短期決策之關係，下列敘述何者正確？', '["攸關成本是指過去已發生之成本", "攸關資訊一定會出現於財務報表中", "變動成本一定是攸關成本", "機會成本是否為攸關成本與公司目前實際運用的產能水準有關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00287', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '在作業基礎成本制（ABC）下，設計成本（designcost）屬於何種成本層級？', '["單位水準成本（unit-levelcosts）", "批次水準成本（batch-levelcosts）", "產品支援成本（product-sustainingcosts）", "設備支援成本（facility-sustainingcosts）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00288', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '在進行採購設備之資本預算決策時，有關淨初始投資金額之敘述何者完全正確？', '["購買新設備之現金流出、營運資金之現金流出，以及處分舊設備所產生之稅後現金流入", "新設備的折舊費用、營運資金之現金流出，以及處分舊設備所產生之稅後現金流入", "購買新設備之現金流出、營運資金之現金流出，以及新設備的折舊費用", "購買新設備之現金流出、新設備的折舊費用，以及處分舊設備所產生之稅後現金流入"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00289', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '關於企業永續發展的敘述，何者錯誤？', '["企業永續發展會提高企業的成本負擔，不過對於企業與社會整體有幫助", "全球各國政府引導企業永續發展是國際趨勢", "企業只有在追求利潤最大化目標，以滿足股東獲利之要求", "企業永續發展的承擔，尤其在環境、社會、治理（ESG）方面表現，有助於提升形象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00290', 'cpa', 'cpa-moex-112-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '下列何者不是自製或外購決策的攸關項目？', '["如果改為向外購買零件時將不會再發生的成本", "目前該零件的直接材料成本", "目前用於生產此零件的特殊機器設備之折舊費用", "可避免的材料處理成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "7577c1ec238e", "answer_pdf_sha1": "9c90102d70c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00291', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'essay', '總機構在中華民國境內之甲公司未依規定辦理 111 年度營利事業所得稅
申報，經稽徵機關催報後仍未申報，該公司111年全年度營業收入 4,000
萬元，其經營行業之同業利潤標準毛利率28%、淨利率 20%，稽徵機關
依所得稅法核定之稅額為何？（5 分）又怠報金為何？（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00292', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'essay', '依所得稅法規定，就下列情況分別計算房屋、土地交易所得之應納稅額：
（未列計算式不予計分）
甲為中華民國境內居住之個人（以下簡稱居住者），其111 年 1月 4 日
以 1,300 萬元購入A房地並於同年8 月1日出售，售價2,000萬元，惟
未提示因取得、改良及移轉而支付之費用，該次交易依土地稅法第30條
第 1 項規定計算之土地漲價總數額 100 萬元，土地增值稅 10 萬元。
（5分）
乙為非居住者，其於 110 年 1 月 5 日以 1,300 萬元購入 B 房地，於 111
年10月10日出售，售價3,000萬元，支付取得、改良及移轉費用160萬
元（如契稅、印花稅、代書費、規費、公證費及仲介費等），該次交易
依土地稅法第 30 條第 1 項計算之土地漲價總數額 200 萬元，土地增
值稅 60萬元。（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00293', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'essay', '甲公司是我國境內採比例扣抵法計算繳納營業稅的兼營營業人，且均無
申請放棄免稅。依加值型及非加值型營業稅法相關規定，回答下列問題：
（未列計算式不予計分）
111 年 2 月份甲公司出售辦公室 1 間，銷售價格為新臺幣 1 億元，其
中建物為4,200萬元，土地為5,800 萬元。假設甲公司當期僅有一筆進
貨 2,100萬元（含稅），無其他進、銷項，甲公司當期營業稅應繳納多
少元？（5 分）
111年9月份甲公司自國外進口營業稅完稅價格3,000萬元的農藥，假
設無其他進口稅費，甲公司此次進口農藥需繳納營業稅多少元？（5分）
該批農藥111年9月份即銷售與乙公司，售價為4,000萬元，如甲公司
當期僅有前開銷售貨物行為，甲公司該期營業稅應繳納多少元？（5分）
如甲公司 111 年度僅有上開進、銷項，甲公司當年度最後一期之調整
稅額若干？（5分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00294', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'essay', '依遺產及贈與稅法規定，回答下列問題：
第 5條所稱之「以贈與論」，包括那些情形？（6 分）
甲於 112年 3月以 3,500 萬元向乙購買 3筆土地，公告土地現值 1,800
萬元，並登記為甲之孫所有，假設甲當年度並無其他贈與行為，計算
本案贈與總額及應納贈與稅額各為若干元。（未列計算式不予計分）（4分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00295', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，納稅義務人111年度綜合所得稅結算申報時，符合下列那一種情形，不得列報 長期照顧特別扣除額或幼兒學前特別扣除額？', '["採各類所得分開計算稅額方式，經減除該2項扣除額後，本人與其配偶適用稅率分別為20%、 12%", "基本所得額650萬元", "符合衛生福利部公告須長期照顧之身心失能者領有身心障礙證明", "納稅義務人列報之子女於106年1月1日出生"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00296', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '個人111年度符合下列何種情形，免依所得基本稅額條例規定計算繳納所得稅？', '["經常居住中華民國境內之個人，有香港來源所得新臺幣200萬元", "經常居住中華民國境內之個人，有基本所得額新臺幣800萬元", "111年度綜合所得稅結算申報有投資抵減稅額新臺幣1萬元", "外國人111年8月至12月受外國公司派遣來我國工作，取得國外薪資新臺幣800萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00297', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法及相關法規規定，營利事業應保持足以正確計算其營利事業所得額之帳簿憑證，下列 何者正確？', '["營利事業設置之帳簿，除未結會計事項外，應至少保存5年", "稽徵機關進行調查時，營利事業未提示各種證明所得額之帳簿、文據，稽徵機關僅得依同業利 潤標準核定其所得額", "營利事業遭受不可抗力災害以致帳簿憑證滅失者，應依規定併同災害損失報請稽徵機關派員勘 查屬實或提出確實證據證明屬實", "營利事業之帳簿憑證因遭受不可抗力而滅失者，稽徵機關應依同業利潤標準核定其所得額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00298', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法及相關法規規定，甲公司108年度新設立，108年度依商業會計法處理之本期稅後淨 利為800萬元，109年4月召開股東會決議分派股利300萬元，另109年12月購買生產用機器 200萬元，其申報108年度未分配盈餘加徵之營利事業所得稅金額，下列何者正確？', '["40萬元", "25萬元", "15萬元", "11萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00299', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '營利事業計算基本所得額時，以所得稅法規定計算之課稅所得額為基礎，加計之各項所得，下列 何者非屬加計項目？', '["依所得稅法規定停徵所得稅之證券交易所得", "依產業創新條例規定智慧財產權研究發展支出加倍減除金額", "依所得稅法規定不計入所得額課稅之股利或盈餘收入", "依國際金融業務條例規定免徵營利事業所得稅之所得額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00300', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '總機構在中華民國境外之A公司，其在臺分公司於107年6月買進一筆土地，與境內甲建設公司 合建，於110年9月興建完成並各自出售土地、房屋，A公司110年度營利事業所得稅申報房地 合一課徵所得稅適用稅率為何？', '["45%", "35%", "20%", "15%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
